+    pub source: usize,
+    /// Target node index.
+    pub target: usize,
+    /// F-statistic for the causality test.
+    pub f_statistic: f32,
+    /// Whether the source Granger-causes the target.
+    pub is_causal: bool,
+    /// Number of lags used.
+    pub lags: usize,
+}
